-- V9__zipcodes_full_seed.sql
-- Adds the full US ZIP-to-county mapping (~31.8k rows covering 50 states + DC),
-- sourced from https://github.com/scpike/us-state-county-zip (CC0).
--
-- County names are matched against the V8 Census seed; the dataset's
-- placeholder rows (non-5-digit codes like 831HH/831XX) are filtered at
-- generation time, as are ~227 rows whose (state, county) pair we do not
-- have seeded (mostly renamed Alaska areas and apostrophe/space mismatches).
--
-- Idempotent via a UNIQUE constraint on (county_id, zipcode) so the V2 sample
-- zips are silently skipped on re-insert. Batched into 1000-row INSERTs to
-- keep per-statement plans reasonable.

ALTER TABLE county_zips
  ADD CONSTRAINT county_zips_county_id_zipcode_unique UNIQUE (county_id, zipcode);

INSERT INTO county_zips (county_id, zipcode)
SELECT c.id, t.zipcode
  FROM counties c
  JOIN states s ON c.state_id = s.id
  JOIN (VALUES
